import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext

class UserRepository {
    private val apiService = NetworkModule.apiService
    
    suspend fun getUserProfile(userId: Int): NetworkResult<User> = withContext(Dispatchers.IO) {
        try {
            val response = apiService.getUserProfile(userId)
            if (response.isSuccessful && response.body() != null) {
                NetworkResult.Success(response.body()!!)
            } else {
                NetworkResult.Error(
                    message = response.message() ?: "Unknown error",
                    code = response.code()
                )
            }
        } catch (e: Exception) {
            NetworkResult.Error(message = e.message ?: "Network error")
        }
    }
    
    suspend fun getAllUsers(): NetworkResult<List<User>> = withContext(Dispatchers.IO) {
